mapper.update:
UPDATE recent_views
SET viewed_at = NOW()
WHERE member_id = #{memberId} AND product_id = #{productId}

mapper.delete:
DELETE FROM recent_views
WHERE member_id = #{memberId}
  AND id NOT IN (
    SELECT id FROM (
        SELECT id FROM recent_views
        WHERE member_id = #{memberId}
        ORDER BY viewed_at DESC
        LIMIT #{keepCount}
    ) AS keep_items
)
